function useInView(threshold = 0.15): [React.RefObject<HTMLDivElement>, boolean] {
  const ref = useRef<HTMLDivElement>(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVis(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, vis];
}

function ZoneCard({ zone, delay, visible }) {
  const [imgError, setImgError] = useState(false);
  return (
    <div
      className="zone-item"
      style={{
        height: zone.height,
        gridColumn: zone.col === "full" ? "1 / -1" : undefined,
        gridRow: zone.rowSpan === 2 ? "span 2" : undefined,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(28px)",
        transition: `opacity 0.75s ease ${delay}s, transform 0.75s ease ${delay}s`,
      }}
    >
      {imgError ? (
        <div style={{ width:"100%", height:"100%", background:"#2c2016", display:"flex", alignItems:"center", justifyContent:"center" }}>
          <span style={{ color:"rgba(255,255,255,.3)", fontSize:12, fontFamily:"Inter,sans-serif" }}>{zone.label}</span>
        </div>
      ) : (
        <img
          src={zone.img}
          alt={zone.label}
          className="zone-img"
          onError={() => setImgError(true)}
          style={{ height:"100%", width:"100%", objectFit:"cover", display:"block" }}
        />
      )}
      <div className="zone-caption-bar">
        <p className="zone-caption">{zone.label}</p>
      </div>
    </div>
  );
}

